using UnityEngine;

public class Anek : MonoBehaviour
{
    public static string GetAnek()
    {
        return aneks[Random.Range(0, aneks.Length)];
    }

    static string[] aneks = 
    {
        "Заблудился как-то долговец и кричит:\n— Люди (протяжно), отзовитесь, кто нибудь аууу.Тут его кто то догоняет и… хлоп сзади по рюкзаку. \nНу он оборачивается, а там стоит кровосос. Грустный такой. И хлюпает ему:\n— Чего орёшь, а?\nУ долговца уже полные штаны ежиков… но он все-таки отвечает:\n— Я того (нервничает), запплутал. Кричу, вот может кто-нибудь услышит (неуверенно)?\nКровосос помолчал, помолчал и говорит ему:\n— Ну я вот услышал (очень недовольно) и чего теперь делать будем?",
        "Встречаются двое сталкеров, ну и один говорит:\n— На днях к Долгу заходил…\n— Ну и? (вопрошает)\n— Чо и? (недовольный) И остался должен. Ха. А потом зашел к Свободе…\n— Ну и чо?\n— И стал СВОБОДЕН!",
        "— То есть вы признаете (официальным тоном), что в нетрезвом виде пытались покинуть территорию Зоны, в районе 12-го блок-поста и имели при себе запрещённые к выносу за ее пределы предметы (вопрошает)?\nНу того запарило третий час под конвоем сидеть… Он и ему говорит:\n— Так… я! Признаю, командир! Всё признаю — вот те крест! Был бы трезвый — \n...\n...\n...\n я бы в жизни мимо вас, уродов,\n...\n с хабаром бы не поперся!",
        "Встречаются двое сталкеров:\n— Слышь (веселым тоном), а ты про Васю, ну того, который ещё в детстве хотел летчиком стать, знаешь?\n— А че с ним?\n— Да он вчера в трамплин попал!\n— Оп-па…\n— Угу\n…\nСбылась, можно сказать, у человека заветная мечта. \n...\nПолетел!",
        "Идёт, значится, молодой сталкер по зоне. Тут бац! РОЩИЦА, и не маленькая, а на карте ее нету. Ну зеленый туда-сюда. Как быть: и соваться стремно, и как лучше обходить неизвестно…\nТут глянь — мужик какой то неподалеку маячит. И ни на долговца[20], ни на наемника не похож.\nОбрадовался, значит, молодой и к нему, так мол и так:\n— А не подскажете, как бы мне рощу вот эту обойти (вопрошает)?\nТот и говорит:\n— Мне тоже в ту сторону, пошли вместе.\nИдут себе. Хорошо, спокойно идут. Молодому скушно стало, он и начинает подлизываться. Вот, значит:\n— Здорово как быть «тертым» сталкером (восхищается), не шугаться от каждого шороха, оружия не таскать много, — у мужика того и правда, ствола видно не было.\nНу тот, стало быть, начинает ржать:\n— Да кого тут вообще бояться (смеётся)?\n— Как кого, — удивляется молодой, — ну (со знанием дела), это, монстров. Контролёры одни чего стоят (восклицает)!\nМужик так помолчал и говорит обиженно:\n— Дурак ты (укоряет)… Если бы сказал зомби или кровососы… Но нас то (восхищаясь) — контролёров! За что «монстрами» обзывать?!",
        "Как-то поймали наемники сталкера. Подошли к колодцу, окунули его головой вниз по пояс.\nЧерез минуту достают и спрашивают:\n— Артефакты, бабло ЕСТЬ (чеканя каждое слово)?!\nОн им:\n— (растерянно) нету…\nОпускают его ещё раз. Достали, спрашивают:\n— Артеффакты, бабло ЕСТЬ (крайне недовольным голосом)?!\n— Да нету (отчаявшись)!\nОпять окунули. И опять спрашивают:\n— Артеффакты, бабло ЕСТЬ (крайне недовольным голосом)?!\nНу тот и не выдержал:\n— Блииин. Вы или ОПУСКАЙТЕ глубже или ДЕРЖИТЕ дольше. ДНО мутное (отчаяние граничащее с недовольством) — ни хрена не видно!",
        "Стоит как-то сталкер у третьего перекрестка и указатели читает:\n«Направо — аномалии и ЧУТОК хабара. Вперед — монстров немерено и СРЕДНЕ хабара. Налево — кабаки, девки и хабара ДОФИГИЩА».\nНу он подумал-подумал и вперед двинулся. Думает:\n— Чёта я про это слыхал… Да забыл блин (расстроившись). Надо будет на Баре у приятелей уточнить — (недоумевает) че за ффигня такая?! кабаки и девки.",
        "Как-то пропал один долговец. Должен был прийти с утра, а нету. Ждут его товарищи, беспокоятся. В конце-концов прибегает. Ну, остальные к нему:\n— Что случилось то (с беспокойством в голосе)? Ты куда пропал?\nА он им:\n— Да тут это (со рассеяностью в голосе)… Значит (торопясь рассказать) решил я с утра тварей в окрестностях немного помочить… Как о-бычно (запинаясь на полуслове), пере-мочил два десятка кро-во-со-сов, пя-ток бюреров, три стаи слепых псов извел под корень. А зомби — так и вообще не считал!\n— Ну это понятно (отмахиваясь)… А что случилось-то (вопрошают)?\n— Да вот захожу я в палатку (с удивлением). Гляжу — а там ТАКОЙ крутой, что даже МНЕ с ним не справиться. (С горечью в голосе) Забыл, что зззеркало у входа. Ну, в общем… обделался я, со страху.",
        "Поймали как-то долговцы свободовца-растамана. И решили, что надо его потрясти — где и чего у свободы спрятано… А он, значит, ни в какую не колется, пока не приперло его покурить.\n— Дайте, — говорит, — пыхнуть. Я вам всеее выложу!\nНу, долговцы вернули ему запас… Он косяк забил, раскурил, сидит кайфует.\n— Ну, — спрашивают, — ГДЕ (недовольно)?\nА он в непонятках:\n— (дружелюбным слащавым голосом) так этаа, рибята. Вы чеее?? Сами ни видите — у вас артефакты прямо под но-гами валяются (прется от смеха)! У, блин (удивлённо)! А теперь и небо пошло в а-лмазах (прется от смеха)! ОФИГЕТЬ!!!",
        "Идет новичек по зоне. Замечтался, оврага не заметил и… как покатится под откос!\nА внизу — мясорубка. Нну сталкер думает:\n— Все… Прощай мама! (с горечью).\nИ тут его кто-то. Цоп!.. Он смотрит… а это зомби его схватил и тянет-тянет теперь куда-то.\nСталкер его и спрашивает:\n— Ззомби, эта (запыхавшись), сспасибо, что от мясорубки спас… А ккуда ты меня тащишь (прийдя в себя)?\nА зомби:\n— Кантраллёр свежее мясо любит (механическим хриплым голосом). Ффарш — не любит. А еде разговаривать нельзя.",
        "Ушел на покой старый сталкер. Сидит себе у камина с ручной собачкой и читает:\n— … В гречческой и римской мифологии (напряженным голосом, вчитываясь в каждое слово) Цербер — чудовищный двухглавый пес. Со змеиным хвостом… Охраняющий вход в подземное царство.\nТут пес:\n— ГАВ!\nСталкер всполошился, за стволом сразу полез. А кругом все… ТИХО.\nОн к собаке:\n— Ты чего, дружок (с ноткой удивления)?\nА он:\n— Гав-гав. Гав-но вваша миффология.",
        "Заходит сталкер в Бар:\n— Бармен! Дай чего-нибудь пожрать (пренебрежительным тоном).\nБармен, значит, начинает:\n— Нуу (со знанием дела и ударением на названиях блюд), вот сегодня есть глаз плоти. В ТОМАТНОМ СОУСЕ. Жжареные лапки снорков. В ТОМАТНОМ СОУСЕ. Из рыбного… Щупальца кровососа. В ТОМАТНОМ СОУСЕ.\nСталкера аж перекосило:\n— Ты, — говорит, — чего это вздумал (возмущённо)?! ЛЮДЕЙ ТРАВИТЬ?\nБармена тоже перекосило.\n— Кто травит!? Я (возглас)?\nСталкер:\n— А что, Я (перекрикивая)!?.. С грибным соусом давай (возмущённо)! Какой нафиг томат?",
        "На краю Саркофага стоят два контролёра.\nПервый так, СОКРУШЁННО:\n— Во блин (в полном шоке)! Штаны упали.\n— Хххаха, — второй так посмотрел на него и говорит равнодушно, — ну и ХРЕН с ним (давясь от смеха)!\nА первый со вздохом таким:\n— Ааааах (с горечью в голосе)… То-то и оно…",
        "Починили свободовцы танк, и в общем решили повоевать на нем. Нууу, там одного чувака приписали, который когда то танкистом был… А он им лекцию читает:\n— Ну, — говорит, — народ! Скажите мне: ЧТО самое главное в танке (чеканя каждое слово)?\n— Пууушка!\n— Ответ неправильный.\n— Броняяяя!\n— МУЙНЯ (кривляет)! Ответ неправильный… Эх (с тоской в голосе) салабоны, вы, салабоны. Самое главное в танке… это не усраться!",
        "Пробираются, значит, по улицам Припяти двое сталкеров.\nОдин — ОПЫТНЫЙ, другой — новичок.\nНу, новичок постоянно сверяется с картой… Бывалый — только ухмыляется.\nТут на одном из перекрестков бывалый как ХЛОПНЕТ себя по лбу.\nВырвал у новичка карту:\n— Точно!.. Ану давай, салага. ВОН к тому дому проберемся (прикрикнул).\nПробрались.\nБывалый:\n— Теперь давай в этот парадняк. ЗАШЛИ. Поднялись по лестнице.\nБывалый говорит:\n— СТОП! Ломай эту дверь (со знанием дела).\nНовичек с раз-бегу выносит дверь.\nБывалый:\n— ДАВАЙ в кухню! ЛОМАЙ вытяжку.\nНовичек, значится, пытается отодрать решетку от стены.\nПыхтит так и спрашивает, с уважением:\n— Слышь, а что хоть за артефакт такой. Что не смог САМ унести (шепотом и удивлённо)?\nА бывалый ему:\n— Какой НАХРЕН артефакт (орет)?!.. Я до аварии в ЭТОЙ квартире жил… А в вентиляции — водку от жены прятал! ДАВАЙ ломай быстрее!",
        "Ззаползает пьяный сталкер в Бар на карачках. Поворачивает к стене И начинает ползти вверх.\nПерелазит на потолок, потом по другой стене переползает к СТОЙКЕ.\nЗАКАЗЫВАЕТ бутылку водки.\nВыпивает.\nДостает из рюкзака артефакт. \nЗАКУСЫВАЕТ.\n\nПосле чего разворачивается И выползает из Бара.\nОдин сталкер обалдел. Ну и говорит другому:\n— ТЫ видал (удивлённо)?\nА тот ему:\n— Уыа (понимающе). Закусил, ППАДЛА (возмущённо). Не те уже времена! (сокрушаясь) Раньше порядочный сталкер арте-фактом за-нююхивал!",
        "Пошли два новичка в Зону. Не успели и пары шагов сделать — как на них кровосос напал.\nНовички, ясное дело, с перепугу стволы по-бросали. И как РВАНУТ в разные стороны.\nКровосос одного из них выбрал. И погнался на ним.\nТОТ на дерево. А кровосос — за ним.\nВторой новичок возвращается. ХВАТАЕТ ствол и даввай, значит, в кровососа стрелять.\nБАХ! — у кровососа правое яйцо в сторону.\nТварь, значит, от боли ревёт, но по дереву дальше лезет.\nТот снова: БАХ! — левое яйцо в сторону. У кровососа КРОВИЩА хлещет. Но он всё равно ВВЕРХ лезет. Только ещё ЗЛЕЕ стал.\nББАХ! — кровососу отрывает последнюю причиндалину. Но он всё равно не останавливается.\nТут с верхушки дерева первый новичок кричит напарнику:\n— В ГОЛОВУ! В голову ему стреляй (очень напуганно). Придурок, он меня не на-силовать собрался.",
        "Приходит раз свободовец К медику на «Янов». И жалуется, мол, плохо ему в последнее время.\nКостоправ, значит, посмотрел его всего. И говорит:\n— Ну что (устало). Придётся тебе полечиться. Травки попить.\nУ свободовца аж глаза на лоб полезли:\n— Ты, доктор, ГОНИШЬ (недовольно)! Ты мне ещё скажи… шприцы покурить.",
        "Два долговца беседуют:\n— Ты не напомнишь мне… КТО я (косясь на другого)? Жаворонок? ИЛИ сова?\n— Ты уже пятый раз у меня спрашиваешь (устало)… Ты ДЯТЕЛ!",
    };
}
